use soroban_sdk::{contract, contractimpl, Address, Env, Symbol, Bytes, String, Vec, symbol_short};

#[contractimpl]
impl EventContract {
    pub fn complex_transfer(env: Env, from: Address, to: Address, amount: i128, meta: Bytes) {
        // VIOLATION: 5 topics (exceeds max of 4)
        env.events().publish((symbol_short!("transfer"), from.clone(), to.clone(), amount, amount), ());

        // VIOLATION: Bytes in topics (large payload type)
        env.events().publish((symbol_short!("log"), Bytes::from_slice(&env, &[1, 2, 3])), ());

        // VIOLATION: String in topics (large payload type)
        env.events().publish((symbol_short!("message"), String::from_str(&env, "hello")), meta);

        // VIOLATION: Vec in topics (large payload type)
        env.events().publish((symbol_short!("batch"), Vec::new(&env)), ());

        // SAFE: 2 plain topics (symbol, Address)
        env.events().publish((symbol_short!("ok"), from), ());

        // SAFE: 4 plain topics (exactly at limit)
        env.events().publish((symbol_short!("swap"), from.clone(), to.clone(), amount), meta);

        // SAFE: 1 plain topic (well within limit)
        env.events().publish((symbol_short!("ping"),), ());

        // VIOLATION: both >4 topics AND large payload
        env.events().publish((symbol_short!("full"), from.clone(), to.clone(), amount, Bytes::from_slice(&env, &[1])), meta);
    }

    pub fn no_events(env: Env, a: Address, b: Address) -> i128 {
        let balance = env.storage().instance().get(&a).unwrap_or(0i128);
        balance
    }
}
